#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int A[M], B[K];
        for (int i = 0; i < M; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < K; i++) {
            scanf("%d", &B[i]);
        }
        int trackedAndIgnored = 0;
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < K; j++) {
                if (A[i] == B[j]) {
                    trackedAndIgnored++;
                }
            }
        }
        int untrackedAndUnignored = N - M - K + trackedAndIgnored;
        printf("%d %d\n", trackedAndIgnored, untrackedAndUnignored);
    }
    return 0;
}

