#include <iostream>
#include <set>
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, M, K;
        cin >> N >> M >> K;
        set<int> ignored, tracked;
        for (int i = 0; i < M; i++) {
            int x;
            cin >> x;
            ignored.insert(x);
        }
        for (int i = 0; i < K; i++) {
            int x;
            cin >> x;
            tracked.insert(x);
        }
        int trackedAndIgnored = 0;
        for (auto it = ignored.begin(); it != ignored.end(); it++) {
            if (tracked.find(*it) != tracked.end()) {
                trackedAndIgnored++;
            }
        }
        int untrackedAndUnignored = N - M - K + trackedAndIgnored;
        cout << trackedAndIgnored << " " << untrackedAndUnignored << endl;
    }
    return 0;
}

